ALTER TYPE "BookingStatus" ADD VALUE IF NOT EXISTS 'TICKETED';
ALTER TYPE "BookingStatus" ADD VALUE IF NOT EXISTS 'CHECKED_IN';
ALTER TYPE "BookingStatus" ADD VALUE IF NOT EXISTS 'COMPLETED';
ALTER TYPE "BookingStatus" ADD VALUE IF NOT EXISTS 'REFUND_REQUESTED';
ALTER TYPE "BookingStatus" ADD VALUE IF NOT EXISTS 'REFUND_APPROVED';
ALTER TYPE "BookingStatus" ADD VALUE IF NOT EXISTS 'REFUND_REJECTED';
ALTER TYPE "BookingStatus" ADD VALUE IF NOT EXISTS 'EXPIRED';
CREATE TABLE IF NOT EXISTS "BookingPassenger" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "firstName" TEXT NOT NULL, "lastName" TEXT NOT NULL, "dateOfBirth" TIMESTAMP(3) NOT NULL, "gender" TEXT, "nationality" TEXT NOT NULL, "passportNumber" TEXT, "passportExpiry" TIMESTAMP(3), "visaDetails" JSONB, "passengerType" TEXT NOT NULL, "emergencyContact" JSONB, "frequentFlyerNumber" TEXT, "mealPreference" TEXT, "medicalAssistance" TEXT, "wheelchairAssistance" BOOLEAN NOT NULL DEFAULT false, "specialRequests" TEXT, CONSTRAINT "BookingPassenger_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "SeatAssignment" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "passengerId" TEXT NOT NULL, "segmentRef" TEXT NOT NULL, "seatNumber" TEXT NOT NULL, "cabin" TEXT NOT NULL, "price" DECIMAL(65,30) NOT NULL DEFAULT 0, "currency" TEXT NOT NULL, "characteristics" TEXT[], "heldUntil" TIMESTAMP(3), "confirmedAt" TIMESTAMP(3), CONSTRAINT "SeatAssignment_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "SeatAssignment_passengerId_fkey" FOREIGN KEY ("passengerId") REFERENCES "BookingPassenger"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "BaggageSelection" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "passengerId" TEXT NOT NULL, "type" TEXT NOT NULL, "quantity" INTEGER NOT NULL, "weightKg" INTEGER, "price" DECIMAL(65,30) NOT NULL DEFAULT 0, "currency" TEXT NOT NULL, CONSTRAINT "BaggageSelection_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "BaggageSelection_passengerId_fkey" FOREIGN KEY ("passengerId") REFERENCES "BookingPassenger"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "AncillarySelection" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "passengerId" TEXT, "code" TEXT NOT NULL, "name" TEXT NOT NULL, "price" DECIMAL(65,30) NOT NULL DEFAULT 0, "currency" TEXT NOT NULL, "metadata" JSONB, CONSTRAINT "AncillarySelection_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "AncillarySelection_passengerId_fkey" FOREIGN KEY ("passengerId") REFERENCES "BookingPassenger"("id") ON DELETE SET NULL ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "BookingTimeline" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "event" TEXT NOT NULL, "message" TEXT NOT NULL, "metadata" JSONB, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "BookingTimeline_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "BookingStatusHistory" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "fromStatus" "BookingStatus", "toStatus" "BookingStatus" NOT NULL, "reason" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "BookingStatusHistory_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "BookingAuditLog" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "actorId" TEXT, "action" TEXT NOT NULL, "metadata" JSONB, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "BookingAuditLog_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "Pnr" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL UNIQUE, "code" TEXT NOT NULL UNIQUE, "provider" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Pnr_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "Ticket" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "passengerId" TEXT NOT NULL, "ticketNumber" TEXT NOT NULL UNIQUE, "eticketPdfBase64" TEXT NOT NULL, "issuedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Ticket_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "Ticket_passengerId_fkey" FOREIGN KEY ("passengerId") REFERENCES "BookingPassenger"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "BoardingPass" ("id" TEXT PRIMARY KEY, "bookingId" TEXT NOT NULL, "passengerId" TEXT NOT NULL, "segmentRef" TEXT NOT NULL, "seatNumber" TEXT, "sequenceNumber" TEXT NOT NULL, "qrPayload" TEXT NOT NULL, "pdfBase64" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "BoardingPass_bookingId_fkey" FOREIGN KEY ("bookingId") REFERENCES "Booking"("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "BoardingPass_passengerId_fkey" FOREIGN KEY ("passengerId") REFERENCES "BookingPassenger"("id") ON DELETE CASCADE ON UPDATE CASCADE);
